// sectionLabelKey returns the i18n key for a section's accessible name, resolved
// from the single-source-of-truth taxonomy (nextSettingsGroups). Used by
// nextSettingsSection to name each <section> landmark (#1339 A2). Falls back to
// "" (no landmark) for an id absent from the taxonomy.
func sectionLabelKey(id string) string {
	for _, g := range nextSettingsGroups() {
		for _, s := range g.Sections {
			if s.ID == id {
				return s.LabelKey
			}
		}
	}
	return ""
}

// tabPanelForSection maps a spec section to the data-tab-panel value its reused
// module keys initial hydration off (#1339). image-cache.js (composed under
// "maintenance") gates loadCacheStats() on [data-tab-panel="general"]; updates.js
// gates fetchAndPopulateUpdateStatus() on [data-tab-panel="updates"]. Both check
// the .hidden CLASS (never set here -- every section is visible in the scrollable
// pane), so emitting the marker lets both modules hydrate eagerly on load.
// Returns "" for sections with no lazy module.
func tabPanelForSection(id string) string {
	switch id {
	case "maintenance":
		return "general"
	case "updates":
		return "updates"
	default:
		return ""
	}
}

